// Standalone end-to-end probe of the DEPLOYED GitHub Pages instance.
//
// A green Deploy job proves the bundle uploaded, not that the running instance
// works. This drives the LIVE https://hologram-technologies.github.io/hologram-ai/
// through the full journey — download → compile → materialize → decode — over the
// hermetic fixture served from 127.0.0.1, and asserts the generated bytes match
// the committed reference transcript EXACTLY. If they match, the deployed build
// (wasm + app) is fresh and end-to-end correct; if it 404s an old asset or the
// bytes drift, this fails.
//
// Two gotchas (see memory `verify-deployed-instance`): Chromium needs
// `--disable-features=PrivateNetworkAccessChecks,LocalNetworkAccessChecks` (a
// public HTTPS page fetching http://127.0.0.1 otherwise stalls on PNA preflight),
// and the chat composer takes the raw user message, not the templated prompt.
import { chromium } from "playwright";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import path from "node:path";
import { startFixtureServer, FIXTURE_REPO } from "./fixture-server.mjs";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "../../..");
const DEPLOY_URL =
  process.env.HAI_DEPLOY_URL || "https://hologram-technologies.github.io/hologram-ai/";
const FIXTURE_DISPLAY = "handshake-tiny (hermetic fixture)";
const HANDSHAKE = ["Hello there!", "How are you today?", "Say goodbye."];

const reference = JSON.parse(
  readFileSync(path.join(ROOT, "oracles/fixture/reference-transcript.json"), "utf8"),
);

function ok(msg) {
  console.log(`  ✓ ${msg}`);
}
function fail(msg) {
  console.error(`  ✗ ${msg}`);
  process.exitCode = 1;
}

const fixture = await startFixtureServer();
const browser = await chromium.launch({
  args: [
    "--disable-features=PrivateNetworkAccessChecks,LocalNetworkAccessChecks",
  ],
});

const consoleErrors = [];
const pageErrors = [];

try {
  console.log(`Probing deployed instance: ${DEPLOY_URL}`);
  const context = await browser.newContext();
  const page = await context.newPage();
  page.on("pageerror", (e) => pageErrors.push(String(e)));
  page.on("console", (m) => {
    if (m.type() === "error") consoleErrors.push(m.text());
  });
  page.on("response", (r) => {
    if (r.status() >= 400 && r.url().includes("/hologram-ai/")) {
      consoleErrors.push(`HTTP ${r.status()} ${r.url()}`);
    }
  });

  // Install the fixture catalogue entry + point the app at the fixture server,
  // exactly as the local BDD world does (data, not code).
  const entry = {
    id: "handshake-tiny",
    hfId: FIXTURE_REPO,
    displayName: FIXTURE_DISPLAY,
    description: "The committed journey fixture.",
    modality: "text-chat",
    size: "tiny",
    approxArchiveMb: 1,
    quantize: "none",
    promptTemplate: reference.template,
    stop: ["\nUser:"],
    chatTurnSeparator: reference.separator,
    maxTokens: reference.max_tokens,
  };
  await page.addInitScript(
    ([base, entryJson]) => {
      localStorage.setItem("hologram_hf_base", base);
      localStorage.setItem("hologram_catalogue_custom", entryJson);
    },
    [fixture.base, JSON.stringify([entry])],
  );

  await page.goto(DEPLOY_URL, { waitUntil: "networkidle" });
  ok(`loaded (title: ${await page.title()})`);

  // Download → Ready.
  await page.goto(`${DEPLOY_URL}#/models`);
  await page.waitForSelector("h1:has-text('Models')");
  const row = page.locator(".list-item", { hasText: FIXTURE_DISPLAY });
  await row.locator("button", { hasText: "Download" }).click();
  await row.locator("button", { hasText: "Ready" }).waitFor({ timeout: 150_000 });
  ok("model downloaded, compiled, materialized → Ready");

  // Chat: greedy (temp 0), the 3-message handshake, compare byte-exact.
  await page.goto(`${DEPLOY_URL}#/chat`);
  await page.waitForSelector("h1:has-text('Chat')");
  const tempInput = page.locator("input[type=number]");
  if (await tempInput.count()) await tempInput.first().fill("0");

  const t0 = Date.now();
  for (let i = 0; i < HANDSHAKE.length; i++) {
    await page.locator(".composer textarea").fill(HANDSHAKE[i]);
    await page.locator(".composer button", { hasText: "Send" }).click();
    await page
      .locator(".composer button", { hasText: "Send" })
      .waitFor({ timeout: 150_000 });
    const bubbles = page.locator(".bubble.assistant .md");
    const got = (await bubbles.nth((await bubbles.count()) - 1).innerText()).trim();
    const want = reference.turns[i].completion.trim();
    if (got === want) {
      ok(`turn ${i} "${HANDSHAKE[i]}" → "${got}" (matches reference)`);
    } else {
      fail(`turn ${i}: deployed "${got}" ≠ reference "${want}"`);
    }
  }
  const elapsed = ((Date.now() - t0) / 1000).toFixed(1);
  console.log(`  3-turn handshake wall time: ${elapsed}s`);

  if (pageErrors.length === 0) ok("no uncaught page errors");
  else fail(`page errors: ${JSON.stringify(pageErrors)}`);
  if (consoleErrors.length === 0) ok("no console errors / 4xx-5xx on app assets");
  else fail(`console errors: ${JSON.stringify(consoleErrors.slice(0, 8))}`);
} finally {
  await browser.close();
  await fixture.close();
}

console.log(process.exitCode ? "\nDEPLOYED PROBE: FAILED" : "\nDEPLOYED PROBE: PASS");
